getwd() 
list.files()
library(tidyverse)
library(readr)
library(dplyr)
library(tidyr)
library(lubridate)
library(stringi)
library(janitor)
library(stringr)
library(gtsummary)
library(flextable)
#loading raw files
data21_raw <- read_csv( "2021VAERSDATA.csv", 
                        col_types = cols(VAERS_ID = col_integer(), 
                                         AGE_YRS = col_double(), 
                                         SEX = col_character(),
                                         RECVDATE = col_character(),
                                         RPT_DATE = col_character(),
                                         VAX_DATE = col_character(),
                                         ONSET_DATE = col_character(),  # Key for timing
                                         .default = col_character()))
head(data21_raw)
vax21_raw <- read_csv("2021VAERSVAX.csv", 
                      locale = locale(encoding = "latin1"),
                      col_types = cols(VAERS_ID = col_integer(),
                                       VAX_TYPE = col_character(),
                                       VAX_MANU = col_character(),
                                       VAX_NAME = col_character(),
                                       VAX_DOSE_SERIES = col_double(),
                                       .default = col_character()))
head(vax21_raw)
symp21_raw <- read_csv("2021VAERSSYMPTOMS.csv", 
                       col_types = cols(VAERS_ID = col_integer(),
                                        SYMPTOM1 = col_character(),
                                        SYMPTOM2 = col_character(),
                                        SYMPTOM3 = col_character(),
                                        SYMPTOM4 = col_character(),
                                        SYMPTOM5 = col_character(),
                                       .default = col_character())) |> select( 
                                         -SYMPTOMVERSION1,
                                         -SYMPTOMVERSION2,
                                         -SYMPTOMVERSION3,
                                         -SYMPTOMVERSION4,
                                         -SYMPTOMVERSION5)
head(symp21_raw)
# Checking file size
dim(data21_raw) #gives number of rows and columns
dim(vax21_raw)
dim(symp21_raw)
#Checking file strucTure
glimpse(data21_raw)
glimpse(vax21_raw)
glimpse(symp21_raw)
#Checking StaTs
summary(data21_raw)
summary(vax21_raw)
summary(symp21_raw)
#Checking for duplicaTes
dup_rawdata21 <- data21_raw |> add_count(VAERS_ID, name = "Yo_no") |> filter(Yo_no > 1) |> arrange(desc(VAERS_ID))
View(dup_rawdata21)
dup_rawvax21 <- vax21_raw |> add_count(VAERS_ID, name = "Yo_no") |> filter(Yo_no > 1) |> arrange(desc(VAERS_ID))
View(dup_rawvax21)
dup_rawsym21 <- symp21_raw |> add_count(VAERS_ID, name = "Yo_no") |> filter(Yo_no > 1) |> arrange(desc(VAERS_ID))
View(dup_rawsym21)
#CleanCleanClean
#1. Data CLeaning
data21_clean <- data21_raw |> filter(
  !is.na(VAERS_ID),
  !is.na(AGE_YRS),
  !is.na(VAX_DATE)) |>   
  mutate(  
    RECVDATE = mdy(RECVDATE, quiet = TRUE),
    RPT_DATE = mdy(RPT_DATE, quiet = TRUE),
    VAX_DATE = mdy(VAX_DATE, quiet = TRUE),
    ONSET_DATE = mdy(ONSET_DATE, quiet = TRUE),
    DATEDIED = mdy(DATEDIED, quiet = TRUE),
    AGE_YRS = as.numeric(AGE_YRS),
    AGE_YRS = ifelse(AGE_YRS < 0 | AGE_YRS > 120, NA_real_, AGE_YRS),
    SEX = case_when(SEX %in% c("F", "M") ~ SEX,TRUE ~ "U" ),
    DAYS_TO_ONSET = as.numeric(ONSET_DATE - VAX_DATE),
    DAYS_TO_REPORT = as.numeric(RECVDATE - VAX_DATE),
    REPORT_YEAR = year(RECVDATE)) |> distinct(VAERS_ID, .keep_all = TRUE) |>  
  select(VAERS_ID, RECVDATE,STATE,AGE_YRS, SEX, RPT_DATE, VAX_DATE, ONSET_DATE, HISTORY, RECOVD, DIED, DATEDIED, L_THREAT,X_STAY, NUMDAYS,DISABLE,DAYS_TO_ONSET,DAYS_TO_REPORT,REPORT_YEAR, HOSPDAYS, SYMPTOM_TEXT, HOSPITAL, ALLERGIES, ER_VISIT, OTHER_MEDS,PRIOR_VAX, ER_ED_VISIT )   
cat("Cleaned DATA:", nrow(data21_clean), "rows\n")
#Doublecheck
head(data21_clean)
#2. Vax CLeaning
vaxCOV21_clean <- vax21_raw |> filter(VAX_DOSE_SERIES != "UNK", 
                                   VAX_MANU != "UNKNOWN MANUFACTURER",
                                   !is.na(VAERS_ID)) |> 
  mutate(
    VAX_MANU = str_to_upper(str_trim(VAX_MANU)),
    VAX_TYPE = str_to_upper(str_trim(VAX_TYPE)),
    VAX_MANU = case_when(
      str_detect(VAX_MANU, "PFIZER") ~ "PFIZER",
      str_detect(VAX_MANU, "MODERNA") ~ "MODERNA",
      str_detect(VAX_MANU, "JANSSEN") ~ "JANSSEN",
      str_detect(VAX_MANU, "GLAXOSMITHKLINE") ~ "GSK",
      str_detect(VAX_MANU, "NOVARTIS") ~ "NOVARTIS",
      str_detect(VAX_MANU, "ASTRAZENECA") ~ "ASTRAZENECA",
      str_detect(VAX_MANU, "NOVAVAX") ~ "NOVAVAX",
      TRUE ~ "OTHER"),
    VAX_TYPE = str_to_upper(str_trim(VAX_TYPE)),
    VAX_TYPE = case_when(
      str_detect(VAX_TYPE, "COVID.*19|COVID.*2") ~ "COVID19",
      str_detect(VAX_TYPE, "FLU|INFLUENZA") ~ "INFLUENZA",
      str_detect(VAX_TYPE, "HPV") ~ "HPV",
      str_detect(VAX_TYPE, "PNEUMO") ~ "PNEUMO",
      str_detect(VAX_TYPE, "SHINGLES|ZOSTER") ~ "ZOSTER",
      TRUE ~ VAX_TYPE),
    VAX_DOSE_SERIES = as.numeric(VAX_DOSE_SERIES),
    VAX_LOT = case_when(
      is.na(VAX_LOT) | VAX_LOT == "" | str_to_upper(str_trim(VAX_LOT)) %in% c("UNKNOWN", "UNK") ~ "UNK", TRUE ~ str_to_upper(str_trim(VAX_LOT))))|>  select(VAERS_ID, VAX_TYPE, VAX_MANU, VAX_DOSE_SERIES, VAX_ROUTE, VAX_SITE, VAX_NAME, VAX_LOT)|> filter(VAX_TYPE == "COVID19")
cat("Loaded:Cleaned_VAX_ROWS:", nrow(vaxCOV21_clean))
View(vaxCOV21_clean)
#Checking for duplicaTes
dup_vaxCOV21_clean <- vaxCOV21_clean |> add_count(VAERS_ID, name = "Yo_no") |> filter(Yo_no > 1) |> arrange(desc(VAERS_ID))
View(dup_vaxCOV21_clean)
#Clean em duplicates
vax21_clean <- vaxCOV21_clean |> arrange(desc(VAX_DOSE_SERIES)) |> group_by(VAERS_ID) |> slice(1) |> ungroup()
nrow(vax21_clean)
View(vax21_clean)
